import axios from "axios";
import React, { useState, useEffect } from "react";
import { Link } from "react-router-dom";

function AddProduct()
{

    const [categorylist, setCategorylist] = React.useState([]);
    const [productInput, setProduct] = useState(
        {
            category_id: '',
            slug: '',
            name: '',
            description: '',

            meta_title: '',
            meta_keyword: '',
            meta_description: '',

            selling_price: '',
            original_price: '',
            quantity: '',
            brand: '',
            featured: '',
            popular: '',
            status: '',
        });
    const [picture, setPicture] = useState([]);

    const handleInput = (e) =>
    {
        e.persist();
        setProduct({ ...productInput, [e.target.name]: e.target.value });
    }

    const handleImage = (e) =>
    {
        setPicture({ image: e.target.files[0] });
    }

    useEffect(() =>
    {
        axios.get(`/api/all-category`).then(res =>
        {
            if (res.data.status === 200)
            {
                // Ensure that we are setting an array to the state
                if (Array.isArray(res.data.categories))
                {
                    setCategorylist(res.data.categories);
                }
            }
        });
    }, []);

    const SubmitProduct = (e) =>
    {
        e.preventDefault();
        const formData = new FormData();
        formData.append('image', picture.image);
        formData.append('category_id', productInput.category_id);
        formData.append('slug', productInput.slug);
        formData.append('name', productInput.name);
        formData.append('description', productInput.description);

        formData.append('meta_title', productInput.meta_title);
        formData.append('meta_keyword', productInput.meta_keyword);
        formData.append('meta_description', productInput.meta_description);

        formData.append('selling_price', productInput.selling_price);
        formData.append('original_price', productInput.original_price);
        formData.append('quantity', productInput.quantity);
        formData.append('brand', productInput.brand);
        formData.append('featured', productInput.featured);
        formData.append('popular', productInput.popular);
        formData.append('status', productInput.status);

    }


    return (
        <div className="container-fluid px-4">
            <div className="card mt-4">
                <div className="card-header">
                    <h4>Add Product
                        <Link to="/admin/view-product" className="btn btn-primary btn-sm float-end">View Product</Link>
                    </h4>
                    <div className="card-body">
                        <form onSubmit={SubmitProduct} encType="multipart/form-data">

                            <ul className="nav nav-tabs" id="myTab" role="tablist">
                                <li className="nav-item" role="presentation">
                                    <button className="nav-link active" id="home-tab" data-bs-toggle="tab" data-bs-target="#home" type="button" role="tab" aria-controls="home-tab-pane" aria-selected="true">Home</button>
                                </li>
                                <li className="nav-item" role="presentation">
                                    <button className="nav-link" id="seotag-tab" data-bs-toggle="tab" data-bs-target="#seotags" type="button" role="tab" aria-controls="seotags" aria-selected="false">SEO Tag</button>
                                </li>
                                <li className="nav-item" role="presentation">
                                    <button className="nav-link" id="otherdetails-tab" data-bs-toggle="tab" data-bs-target="#otherdetails" type="button" role="tab" aria-controls="otherdetails" aria-selected="false">Other Details</button>
                                </li>
                            </ul>

                            <div className="tab-content" id="myTabContent">

                                <div className="tab-pane card body border fade show active" id="home" role="tabpanel" aria-labelledby="home-tab" tabindex="0">

                                    <div className="form-group mb-3">
                                        <label> Select Category</label>
                                        <select
                                            name="category_id"
                                            onChange={handleInput}
                                            value={productInput.category_id}
                                            className="form-control">
                                            <option>Select Category</option>
                                            {
                                                categorylist.map((item) =>
                                                {
                                                    return (
                                                        <option value={item.id} key={item.id}>{item.name}</option>
                                                    )
                                                })
                                            }
                                        </select>


                                    </div>

                                    <div className="form-group mb-3">
                                        <label>Product Slug</label>
                                        <input
                                            type="text"
                                            name="slug"
                                            onChange={handleInput}
                                            value={productInput.slug} className="form-control" />
                                    </div>

                                    <div className="form-group mb-3">
                                        <label>Product Name</label>
                                        <input
                                            type="text"
                                            name="name"
                                            onChange={handleInput}
                                            value={productInput.name} className="form-control" />
                                    </div>

                                    <div className="form-group mb-3">
                                        <label>Description</label>
                                        <input
                                            type="text"
                                            name="description"
                                            onChange={handleInput}
                                            value={productInput.description} className="form-control" />
                                    </div>
                                </div>

                                <div className="tab-pane card body border fade show active" id="seotags" role="tabpanel" aria-labelledby="seotags-tab" tabindex="0">

                                    <div className="form-group mb-3">
                                        <label>Meta Title</label>
                                        <input
                                            type="text"
                                            name="meta_title"
                                            onChange={handleInput}
                                            value={productInput.meta_title} className="form-control" />
                                    </div>
                                    <div className="form-group mb-3">
                                        <label>Meta Keyword</label>
                                        <input
                                            type="text"
                                            name="meta_keyword"
                                            onChange={handleInput}
                                            value={productInput.meta_keyword} className="form-control" />
                                    </div>
                                    <div className="form-group mb-3">
                                        <label>Meta Description</label>
                                        <input
                                            type="text"
                                            name="meta_description"
                                            onChange={handleInput}
                                            value={productInput.meta_description} className="form-control" />
                                    </div>
                                </div>

                                <div className="tab-pane card body border fade show active" id="otherdetails" role="tabpanel" aria-labelledby="otherdetails-tab" tabindex="0">

                                    <div className="row">
                                        <div className="col-md-4 form-group mb-3">
                                            <label>Selling Price</label>
                                            <input
                                                type="text"
                                                name="selling_price"
                                                onChange={handleInput}
                                                value={productInput.selling_price} className="form-control" />
                                        </div>
                                        <div className="col-md-4 form-group mb-3">
                                            <label>Original Price</label>
                                            <input
                                                type="text"
                                                name="original_price"
                                                onChange={handleInput}
                                                value={productInput.original_price} className="form-control" />

                                        </div>
                                        <div className="col-md-4 form-group mb-3">
                                            <label>Quantity</label>
                                            <input
                                                type="text"
                                                name="quantity"
                                                onChange={handleInput}
                                                value={productInput.quantity} className="form-control" />
                                        </div>
                                        <div className="col-md-4 form-group mb-3">
                                            <label>Brand</label>
                                            <input
                                                type="text"
                                                name="brand"
                                                onChange={handleInput}
                                                value={productInput.brand} className="form-control" />
                                        </div>

                                        <div className="col-md-4 form-group mb-3">
                                            <label>Featured (checked=shown)</label>
                                            <input
                                                type="checkbox"
                                                name="featured"
                                                onChange={handleInput}
                                                value={productInput.featured} className="form-control" />
                                        </div>
                                        <div className="col-md-4 form-group mb-3">
                                            <label>Popular (checked=shown)</label>
                                            <input
                                                type="checkbox"
                                                name="popular"
                                                onChange={handleInput}
                                                value={productInput.popular} className="form-control" />
                                        </div>
                                        <div className="col-md-4 form-group mb-3">
                                            <label>Status (checked=hidden)</label>
                                            <input
                                                type="checkbox"
                                                name="status"
                                                onChange={handleInput}
                                                value={productInput.status} className="form-control" />
                                        </div>
                                    </div>

                                </div>
                            </div>

                            <button type="submit" className="btn btn-primary px-4 me-2">Submit</button>

                        </form>
                    </div>
                </div>
            </div>
        </div>
    )
}
export default AddProduct;
